#include <bits/stdc++.h>
using namespace std;
int n,m;
int dp[800005];
struct node
{
	int a,b;

} cow[405];
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) cin>>cow[i].a>>cow[i].b;
	memset(dp,-0x3f,sizeof(dp));
	dp[400000]=0;
	for(int i=1;i<=n;i++)
	{
		if(cow[i].a>=0)
		{
			for(int j=800000;j>=cow[i].a;j--)
			{
				dp[j]=max(dp[j],dp[j-cow[i].a]+cow[i].b);
			}
		}
		else
		{	
			for(int j=0;j<=800000+cow[i].a;j++)
			{
				dp[j]=max(dp[j],dp[j-cow[i].a]+cow[i].b);
			}
		}
	}
	int maxx=-0x3f3f3f3f;
	for(int i=400000;i<=800000;i++)
	{
		if(dp[i]>=0)
		{
			maxx=max(maxx,dp[i]+i-400000);
		}
	}
	cout<<maxx;
	return 0;
}
